CREATE TABLE `accounts` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `account_group_id` int(20) DEFAULT NULL,
  `group` varchar(255) DEFAULT NULL,
  `title` varchar(100) DEFAULT NULL,
  `entity_type` varchar(100) DEFAULT NULL,
  `name` varchar(100) DEFAULT NULL,
  `role` varchar(100) DEFAULT NULL,
  `status` varchar(200) DEFAULT NULL,
  `opening_balance` varchar(255) DEFAULT NULL,
  `mobile_number` varchar(20) DEFAULT NULL,
  `email` varchar(100) DEFAULT NULL,
  `gstin` varchar(50) DEFAULT NULL,
  `gst_registered_name` varchar(100) DEFAULT NULL,
  `business_name` varchar(100) DEFAULT NULL,
  `additional_business_name` varchar(100) DEFAULT NULL,
  `display_name` varchar(100) DEFAULT NULL,
  `phone_number` varchar(20) DEFAULT NULL,
  `fax` varchar(50) DEFAULT NULL,
  `account_number` varchar(50) DEFAULT NULL,
  `account_name` varchar(100) DEFAULT NULL,
  `bank_name` varchar(100) DEFAULT NULL,
  `account_type` varchar(50) DEFAULT NULL,
  `branch_name` varchar(100) DEFAULT NULL,
  `ifsc_code` varchar(20) DEFAULT NULL,
  `pan` varchar(20) DEFAULT NULL,
  `tan` varchar(20) DEFAULT NULL,
  `tds_slab_rate` varchar(50) DEFAULT NULL,
  `currency` varchar(20) DEFAULT NULL,
  `terms_of_payment` varchar(100) DEFAULT NULL,
  `reverse_charge` varchar(20) DEFAULT NULL,
  `export_sez` varchar(50) DEFAULT NULL,
  `shipping_address_line1` varchar(255) DEFAULT NULL,
  `shipping_address_line2` varchar(255) DEFAULT NULL,
  `shipping_city` varchar(100) DEFAULT NULL,
  `shipping_pin_code` varchar(20) DEFAULT NULL,
  `shipping_state` varchar(100) DEFAULT NULL,
  `shipping_state_code` varchar(5) DEFAULT NULL,
  `shipping_country` varchar(100) DEFAULT NULL,
  `shipping_branch_name` varchar(100) DEFAULT NULL,
  `shipping_gstin` varchar(50) DEFAULT NULL,
  `billing_address_line1` varchar(255) DEFAULT NULL,
  `billing_address_line2` varchar(255) DEFAULT NULL,
  `billing_city` varchar(100) DEFAULT NULL,
  `billing_pin_code` varchar(20) DEFAULT NULL,
  `billing_state` varchar(100) DEFAULT NULL,
  `billing_state_code` varchar(5) DEFAULT NULL,
  `billing_country` varchar(100) DEFAULT NULL,
  `billing_branch_name` varchar(100) DEFAULT NULL,
  `billing_gstin` varchar(50) DEFAULT NULL,
  `password` varchar(100) DEFAULT NULL,
  `staffid` int(100) DEFAULT NULL,
  `assigned_staff` varchar(100) DEFAULT NULL,
  `staff_incentive` varchar(200) DEFAULT NULL,
  `discount` decimal(10,2) DEFAULT 0.00,
  `Target` decimal(15,2) DEFAULT 100000.00,
  `otp` varchar(6) DEFAULT NULL,
  `otp_expires_at` datetime DEFAULT NULL,
  `otp_used` tinyint(1) DEFAULT 0,
  `alternate_number` varchar(15) DEFAULT NULL,
  `date_of_birth` date DEFAULT NULL,
  `gender` varchar(10) DEFAULT NULL,
  `address` text DEFAULT NULL,
  `designation` varchar(100) DEFAULT NULL,
  `department` varchar(100) DEFAULT NULL,
  `joining_date` date DEFAULT NULL,
  `incentive_percent` decimal(5,2) DEFAULT NULL,
  `salary` decimal(10,2) DEFAULT NULL,
  `bank_account_number` varchar(30) DEFAULT NULL,
  `upi_id` varchar(100) DEFAULT NULL,
  `aadhaar_number` varchar(20) DEFAULT NULL,
  `blood_group` varchar(5) DEFAULT NULL,
  `emergency_contact` varchar(15) DEFAULT NULL,
  `credit_limit` int(255) DEFAULT NULL,
  `unpaid_amount` varchar(250) DEFAULT NULL,
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `score` decimal(5,2) DEFAULT 0.00,
  `score_tier` varchar(20) DEFAULT 'Basic',
  `last_score_calculated` datetime DEFAULT NULL,
  `score_details` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`score_details`)),
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `balance_amount` decimal(15,2) DEFAULT 0.00,
  `current_score` decimal(5,2) DEFAULT 0.00,
  `target_achieved` decimal(15,2) DEFAULT 0.00,
  `achievement_percentage` decimal(5,2) DEFAULT 0.00,
  `last_target_calculated` datetime DEFAULT NULL,
  `target_period` varchar(50) DEFAULT 'monthly',
  `score_marks` decimal(5,2) DEFAULT 0.00,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=75 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

