CREATE TABLE `batches` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `product_id` int(11) NOT NULL,
  `batch_number` varchar(255) DEFAULT NULL,
  `group_by` varchar(255) DEFAULT NULL,
  `mfg_date` varchar(255) DEFAULT NULL,
  `exp_date` varchar(255) DEFAULT NULL,
  `product_type` varchar(20) DEFAULT NULL,
  `quantity` varchar(255) DEFAULT NULL,
  `opening_stock` varchar(255) DEFAULT NULL,
  `stock_in` varchar(255) DEFAULT NULL,
  `stock_out` varchar(255) DEFAULT NULL,
  `cost_price` varchar(255) DEFAULT NULL,
  `selling_price` varchar(255) DEFAULT NULL,
  `purchase_price` varchar(255) DEFAULT NULL,
  `mrp` varchar(255) DEFAULT NULL,
  `min_sale_price` varchar(200) DEFAULT NULL,
  `batch_price` varchar(255) DEFAULT NULL,
  `barcode` varchar(255) DEFAULT NULL,
  `remark` varchar(300) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `flash_sale_status` enum('active','inactive') DEFAULT 'active',
  `opening_stock_date` date DEFAULT NULL,
  `weight` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `batches_ibfk_1` (`product_id`),
