CREATE TABLE `offers` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `description` text DEFAULT NULL,
  `discount_percentage` decimal(5,2) NOT NULL,
  `minimum_amount` decimal(10,2) DEFAULT 0.00,
  `valid_from` date NOT NULL,
  `valid_until` date NOT NULL,
  `image_url` varchar(500) DEFAULT NULL,
  `offer_type` enum('bogo','expiry','clearance','seasonal','hourly','limited_stock','global','category') DEFAULT NULL,
  `status` enum('active','inactive') DEFAULT 'active',
  `category_name` varchar(255) DEFAULT NULL,
  `category_id` int(11) DEFAULT NULL,
  `product_name` varchar(255) DEFAULT NULL,
  `product_id` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `offer_scope` enum('global','category') NOT NULL,
  `purchase_limit` varchar(50) DEFAULT NULL,
  `offer` varchar(50) DEFAULT NULL,
  `company_id` varchar(50) DEFAULT NULL,
  `company_name` varchar(255) DEFAULT NULL,
  `buy_quantity` int(11) DEFAULT NULL,
  `get_quantity` int(11) DEFAULT NULL,
  `terms_conditions` text DEFAULT NULL,
  `start_time` time DEFAULT NULL,
  `end_time` time DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=33 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

