CREATE TABLE `order_items` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `order_number` varchar(50) DEFAULT NULL,
  `item_name` varchar(255) DEFAULT NULL,
  `product_id` int(11) DEFAULT NULL,
  `mrp` decimal(10,2) DEFAULT NULL,
  `sale_price` decimal(10,2) DEFAULT NULL,
  `edited_sale_price` decimal(10,2) DEFAULT NULL,
  `credit_charge` decimal(10,2) DEFAULT NULL,
  `customer_sale_price` decimal(10,2) DEFAULT NULL,
  `final_amount` decimal(10,2) DEFAULT NULL,
  `quantity` int(11) DEFAULT NULL,
  `total_amount` decimal(10,2) DEFAULT NULL,
  `discount_percentage` decimal(5,2) DEFAULT NULL,
  `discount_amount` decimal(10,2) DEFAULT NULL,
  `taxable_amount` decimal(10,2) DEFAULT NULL,
  `tax_percentage` decimal(5,2) DEFAULT NULL,
  `tax_amount` decimal(10,2) DEFAULT NULL,
  `item_total` decimal(10,2) DEFAULT NULL,
  `credit_period` int(11) DEFAULT NULL,
  `invoice_number` varchar(50) NOT NULL,
  `invoice_date` date DEFAULT NULL,
  `invoice_status` tinyint(1) NOT NULL DEFAULT 0,
  `created_at` datetime(6) DEFAULT current_timestamp(6),
  `updated_at` datetime(6) DEFAULT current_timestamp(6) ON UPDATE current_timestamp(6),
  `credit_percentage` decimal(5,2) DEFAULT NULL,
  `sgst_percentage` decimal(5,2) DEFAULT NULL,
  `sgst_amount` decimal(10,2) DEFAULT NULL,
  `cgst_percentage` decimal(5,2) DEFAULT NULL,
  `cgst_amount` decimal(10,2) DEFAULT NULL,
  `discount_applied_scheme` varchar(255) DEFAULT NULL,
  `stock_status` enum('AVAILABLE','OUT_OF_STOCK','INSUFFICIENT_STOCK') DEFAULT 'AVAILABLE',
  `admin_approval` varchar(50) DEFAULT 'pending',
  `flash_offer` varchar(50) DEFAULT '0',
  `buy_quantity` int(11) DEFAULT 0,
  `get_quantity` int(11) DEFAULT 0,
  `net_price` varchar(200) DEFAULT NULL,
  `weight` varchar(255) DEFAULT NULL,
  `order_mode` varchar(20) DEFAULT 'NULL',
  PRIMARY KEY (`id`),
  KEY `order_number` (`order_number`)
) ENGINE=InnoDB AUTO_INCREMENT=314 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

