CREATE TABLE `orders` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `order_number` varchar(50) NOT NULL,
  `customer_id` int(11) DEFAULT NULL,
  `retailer_mobile` varchar(220) DEFAULT NULL,
  `customer_name` varchar(150) DEFAULT NULL,
  `order_total` decimal(10,2) DEFAULT NULL,
  `discount_amount` decimal(10,2) DEFAULT NULL,
  `taxable_amount` decimal(10,2) DEFAULT NULL,
  `tax_amount` decimal(10,2) DEFAULT NULL,
  `net_payable` decimal(10,2) DEFAULT NULL,
  `credit_period` decimal(10,2) DEFAULT NULL,
  `estimated_delivery_date` date DEFAULT NULL,
  `order_placed_by` int(11) DEFAULT NULL,
  `ordered_by` varchar(255) DEFAULT NULL,
  `staff_id` varchar(255) DEFAULT NULL,
  `assigned_staff` varchar(255) DEFAULT NULL,
  `order_mode` enum('KACHA','PAKKA') DEFAULT NULL,
  `invoice_number` varchar(50) DEFAULT NULL,
  `invoice_date` date DEFAULT NULL,
  `invoice_status` tinyint(1) NOT NULL DEFAULT 0,
  `order_status` enum('Pending','Invoice','Cancelled') DEFAULT 'Pending',
  `staff_incentive` varchar(200) DEFAULT NULL,
  `approval_status` varchar(255) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `modification_required` tinyint(1) DEFAULT 0,
  `modification_reason` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `order_number` (`order_number`),
  KEY `customer_id` (`customer_id`),
  KEY `order_placed_by` (`order_placed_by`),
  CONSTRAINT `orders_ibfk_1` FOREIGN KEY (`customer_id`) REFERENCES `accounts` (`id`),
  CONSTRAINT `orders_ibfk_2` FOREIGN KEY (`order_placed_by`) REFERENCES `accounts` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=275 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

