CREATE TABLE `password_resets` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `email` varchar(255) NOT NULL,
  `otp` varchar(6) NOT NULL,
  `used` tinyint(1) DEFAULT 0,
  `expires_at` datetime NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;



CREATE TABLE `products` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `group_by` text DEFAULT NULL,
  `goods_name` varchar(255) DEFAULT NULL,
  `category_id` varchar(100) DEFAULT NULL,
  `company_id` varchar(100) DEFAULT NULL,
  `price` varchar(100) DEFAULT NULL,
  `weight` varchar(255) DEFAULT NULL,
  `purchase_price` int(200) DEFAULT NULL,
  `inclusive_gst` varchar(10) DEFAULT NULL,
  `gst_rate` varchar(10) DEFAULT NULL,
  `product_type` varchar(20) DEFAULT NULL,
  `non_taxable` varchar(10) DEFAULT NULL,
  `net_price` varchar(100) DEFAULT NULL,
  `hsn_code` varchar(50) DEFAULT NULL,
  `unit` varchar(50) DEFAULT NULL,
  `cess_rate` varchar(10) DEFAULT NULL,
  `cess_amount` varchar(100) DEFAULT NULL,
  `sku` varchar(100) DEFAULT NULL,
  `min_stock_alert` varchar(100) DEFAULT NULL,
  `max_stock_alert` varchar(100) DEFAULT NULL,
  `description` varchar(500) DEFAULT NULL,
  `maintain_batch` tinyint(1) DEFAULT 0,
  `can_be_sold` tinyint(1) DEFAULT NULL,
  `images` varchar(255) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `min_sale_price` int(200) DEFAULT NULL,
  `mrp` varchar(222) DEFAULT NULL,
  `purchase_product_id` varchar(50) DEFAULT NULL,
  `opening_stock_date` date DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1244 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

