CREATE TABLE `voucher` (
  `VoucherID` int(11) NOT NULL AUTO_INCREMENT,
  `TransactionType` varchar(50) DEFAULT NULL,
  `VchNo` varchar(100) DEFAULT NULL,
  `product_id` int(11) DEFAULT NULL,
  `batch_id` varchar(200) DEFAULT NULL,
  `InvoiceNumber` varchar(100) DEFAULT NULL,
  `order_number` varchar(50) DEFAULT NULL,
  `Date` date DEFAULT NULL,
  `PaymentTerms` text DEFAULT NULL,
  `Freight` decimal(15,2) DEFAULT NULL,
  `TotalPacks` int(11) DEFAULT NULL,
  `TaxAmount` decimal(15,2) DEFAULT NULL,
  `Subtotal` decimal(15,2) DEFAULT NULL,
  `BillSundryAmount` decimal(15,2) DEFAULT NULL,
  `TotalAmount` decimal(15,2) DEFAULT NULL,
  `ChequeNo` varchar(100) DEFAULT NULL,
  `ChequeDate` date DEFAULT NULL,
  `BankName` varchar(255) DEFAULT NULL,
  `AccountID` int(11) DEFAULT NULL,
  `AccountName` varchar(255) DEFAULT NULL,
  `business_name` varchar(350) DEFAULT NULL,
  `PartyID` int(11) DEFAULT NULL,
  `PartyName` varchar(255) DEFAULT NULL,
  `BasicAmount` decimal(15,2) DEFAULT NULL,
  `ValueOfGoods` decimal(15,2) DEFAULT NULL,
  `EntryDate` datetime DEFAULT NULL,
  `SGSTPercentage` decimal(5,2) DEFAULT NULL,
  `CGSTPercentage` decimal(5,2) DEFAULT NULL,
  `IGSTPercentage` decimal(5,2) DEFAULT NULL,
  `SGSTAmount` decimal(15,2) DEFAULT NULL,
  `CGSTAmount` decimal(15,2) DEFAULT NULL,
  `IGSTAmount` decimal(15,2) DEFAULT NULL,
  `TaxSystem` varchar(50) DEFAULT NULL,
  `paid_amount` decimal(15,2) DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `balance_amount` decimal(15,2) DEFAULT NULL,
  `status` enum('Pending','Partial','Paid') NOT NULL DEFAULT 'Pending',
  `paid_date` date DEFAULT NULL,
  `pdf_data` longblob DEFAULT NULL,
  `DC` varchar(10) DEFAULT NULL,
  `staffid` int(11) DEFAULT NULL,
  `assigned_staff` varchar(255) DEFAULT NULL,
  `pdf_file_name` varchar(255) DEFAULT NULL,
  `transaction_proof` varchar(255) DEFAULT NULL,
  `pdf_created_at` datetime DEFAULT NULL,
  `note_preview` varchar(540) DEFAULT NULL,
  `description_preview` varchar(300) DEFAULT NULL,
  `order_mode` enum('KACHA','PAKKA') DEFAULT NULL,
  `staff_incentive` varchar(200) DEFAULT NULL,
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `due_date` date DEFAULT NULL,
  `total_discount` decimal(10,2) DEFAULT 0.00,
  `total_credit_charge` decimal(10,2) DEFAULT 0.00,
  `data_type` varchar(50) DEFAULT NULL,
  `retailer_mobile` varchar(20) DEFAULT NULL,
  `payment_method` varchar(50) DEFAULT NULL,
  `flash_offer` varchar(55) DEFAULT NULL,
  PRIMARY KEY (`VoucherID`)
) ENGINE=InnoDB AUTO_INCREMENT=943 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

